def big_end(Fp, Pb_big, ldb_ratio):
      db_req = (Fp / (Pb_big * ldb_ratio)) ** 0.5
      lb_req = ldb_ratio * db_req
      return {
          "db_req": db_req,
          "lb_req": lb_req,
      }

def bolt_req(r, Wr, n, lc, Csteel, Nb, sig_bolt_allow):
      Fi = 4.03e-3 * r * (n**2) * Wr * (1 + (r / lc))
      Fin = Fi / 2
      Ab_req = (Fin / Csteel) ** (1 / 1.418)
      Boltd_req = (4 * Ab_req / np.pi) ** 0.5
      return {
          "Ab_req": Ab_req,
          "Fi": Fi,
          "Boltd_req": Boltd_req,
      }

def small_end(Fp, Pb_small, lds_ratio):
      ds_req = (Fp / (Pb_small * lds_ratio)) ** 0.5
      ls_req = lds_ratio * ds_req
      return {
          "ds_req": ds_req,
          "ls_req": ls_req,
      }

def cap_req(Fi, db_req, Bolt_req, sig_y_mat):
      len = db_req + (2 * 3) + Bolt_req + 5
      tcap_req = ((Fi * len) / (db_req * sig_y_mat)) ** 0.5
      return {
          "tcap_req": tcap_req,
          "len": len,
      }
